import { create } from 'zustand';
import { useShallow } from 'zustand/react/shallow';
import type { Board, BubbleSlot, Mode, DifficultyPreset } from '../engine/index.js';
import {
  emptyBoard, fillStartRows, simulateShot, tickPity,
  isWon, isLost, makeQueue, deterministicRng, dailySeed, dailyDifficulty,
  DIFFICULTY, makeBoard,
} from '../engine/index.js';
import { dailyPlayfieldFor } from '../features/daily/daily-loader.js';
import { bus } from '../lib/bus.js';
import { useStreakStore } from './streak-store.js';

const RUN_KEY = 'bilko_fizzpop_run_v1';

export interface SerializedSave {
  v: 1;
  mode: Mode;
  seed: number | null;
  cells: (BubbleSlot)[];
  rows: number;
  cols: number;
  tileDiameter: number;
  pityRemaining: number;
  pityMax: number;
  nextBubble: BubbleSlot;
  queuedBubble: BubbleSlot;
  drawCount: number;
  shotsUsed: number;
  score: number;
  startedAt: number;
  timeMs: number;
  par: number | null;
  dailyIso: string | null;
}

export interface RunState {
  mode: Mode | null;         // null = at mode-select screen
  seed: number | null;       // present for daily; deterministic
  board: Board;
  nextBubble: BubbleSlot;    // currently in cannon
  queuedBubble: BubbleSlot;  // visible in pill
  drawCount: number;         // for rainbow cadence parity
  shotsUsed: number;
  score: number;
  startedAt: number;         // epoch ms
  timeMs: number;            // accumulated, paused-aware
  paused: boolean;
  solved: boolean;
  lost: boolean;
  par: number | null;        // daily only
  dailyIso: string | null;   // YYYY-MM-DD when mode === 'daily'
}

interface Actions {
  startRun: (opts: { mode: Mode; seed?: number; date?: Date }) => void;
  recordShot: (angleDeg: number) => void;
  swapQueue: () => void;
  pause: (on: boolean) => void;
  resume: () => void;
  abandonRun: () => void;
  loadFromSave: (s: SerializedSave) => void;
}

export const useStore = create<RunState & { actions: Actions }>((set, get) => {
  // queue holder; reconstructed on load
  let queue: ReturnType<typeof makeQueue> | null = null;

  return {
    mode: null, seed: null,
    board: emptyBoard(),
    nextBubble: null, queuedBubble: null, drawCount: 0,
    shotsUsed: 0, score: 0,
    startedAt: 0, timeMs: 0, paused: false,
    solved: false, lost: false,
    par: null, dailyIso: null,

    actions: {
      startRun: ({ mode, seed: seedArg, date }) => {
        const seed = seedArg ?? (mode === 'daily' && date
          ? dailySeed(date)
          : Math.floor(Math.random() * 0xffffffff));
        const rng = deterministicRng(seed);
        let preset: DifficultyPreset;
        let par: number | null = null;
        let dailyIso: string | null = null;
        if (mode === 'daily') {
          const d = date ?? new Date();
          const cfg = dailyDifficulty(d);
          const baseMode = cfg.mode as 'beginner' | 'intermediate' | 'expert';
          preset = { ...DIFFICULTY[baseMode], pityMax: cfg.pityMax };
          par = cfg.par;
          dailyIso = isoDate(d);
        } else {
          preset = DIFFICULTY[mode as 'beginner' | 'intermediate' | 'expert'];
        }
        let board = emptyBoard({ rows: 14, cols: 8, tileDiameter: 64 });
        if (mode === 'daily') {
          // Use deterministic hand-curated daily playfield (PRD 104)
          const d = date ?? new Date();
          board = dailyPlayfieldFor(d).board;
        } else {
          board = { ...board, pityRemaining: preset.pityMax, pityMax: preset.pityMax };
          board = fillStartRows(board, preset.startRows, rng, preset);
        }
        queue = makeQueue({ rng, difficulty: preset, boardSnapshot: () => get().board });
        const next = queue.next();
        const queued = queue.peek();
        set({
          mode, seed, board,
          nextBubble: next, queuedBubble: queued, drawCount: 2,
          shotsUsed: 0, score: 0,
          startedAt: Date.now(), timeMs: 0, paused: false,
          solved: false, lost: false,
          par, dailyIso,
        });
        bus.emit('gameStarted', { mode: mode as 'daily' | 'beginner' | 'intermediate' | 'expert', seed });
        debouncePersist();
      },

      recordShot: (angleDeg: number) => {
        const s = get();
        if (s.solved || s.lost || s.paused || !s.mode || !queue) return;
        const color = s.nextBubble;
        if (color === null) return;
        bus.emit('bubbleFired', { color: color as any, angleDeg, startedAtMs: Date.now() });
        const result = simulateShot(s.board, angleDeg, color);
        let nextBoard = result.snappedBoard;
        if (result.targetCell) bus.emit('bubbleSnapped', { color: color as any, cell: result.targetCell });
        if (result.popped.length) bus.emit('clusterPopped', { cells: result.popped, color: color as any, size: result.popped.length });
        if (result.dropped.length) bus.emit('floatersDropped', { cells: result.dropped, count: result.dropped.length });

        // Pity tick: non-popping shot decrements; popping shot resets
        let extraDraws = 0;
        if (result.popped.length === 0) {
          const pityTick = tickPity(nextBoard, false);
          nextBoard = pityTick.board;
          if (pityTick.rowAdded) {
            const pityRow = nextBoard.cells.slice() as BubbleSlot[];
            for (let col = 0; col < nextBoard.cols; col++) {
              pityRow[col] = queue!.next();
              extraDraws++;
            }
            nextBoard = { ...nextBoard, cells: Object.freeze(pityRow) };
            bus.emit('rowAdded', { reason: 'pity' });
          }
          bus.emit('pityChanged', { remaining: nextBoard.pityRemaining, max: nextBoard.pityMax });
        } else {
          const pityTick = tickPity(nextBoard, true);
          nextBoard = pityTick.board;
          bus.emit('pityChanged', { remaining: nextBoard.pityRemaining, max: nextBoard.pityMax });
        }

        const queuedNext = queue!.next();
        const peeked = queue!.peek();
        const newScore = s.score + result.score;
        const newShots = s.shotsUsed + 1;
        const won = isWon(nextBoard, s.mode);
        const lost = !won && isLost(nextBoard);

        set({
          board: nextBoard,
          nextBubble: queuedNext,
          queuedBubble: peeked,
          drawCount: s.drawCount + 1 + extraDraws,
          shotsUsed: newShots,
          score: newScore,
          solved: won, lost,
        });
        debouncePersist();

        if (won) {
          bus.emit('gameWon', {
            mode: s.mode!, shotsUsed: newShots, par: s.par ?? undefined,
            score: newScore, timeMs: get().timeMs,
          });
          try { localStorage.removeItem(RUN_KEY); } catch { /* no-op */ }
        } else if (lost) {
          bus.emit('gameLost', { mode: s.mode!, shotsUsed: newShots, score: newScore, timeMs: get().timeMs });
          try { localStorage.removeItem(RUN_KEY); } catch { /* no-op */ }
        }
      },

      swapQueue: () => {
        const s = get();
        if (!s.nextBubble || !s.queuedBubble) return;
        set({ nextBubble: s.queuedBubble, queuedBubble: s.nextBubble });
        debouncePersist();
      },

      pause: (on) => set({ paused: on }),

      resume: () => {
        try {
          const raw = localStorage.getItem(RUN_KEY);
          if (!raw) return;
          const blob = JSON.parse(raw) as SerializedSave;
          if (blob.v !== 1) { localStorage.removeItem(RUN_KEY); return; }
          // Don't restore a daily that's already been completed today
          if (blob.mode === 'daily' && blob.dailyIso) {
            const { completed } = useStreakStore.getState();
            if (completed.includes(blob.dailyIso)) return;
          }
          get().actions.loadFromSave(blob);
        } catch {
          try { localStorage.removeItem(RUN_KEY); } catch { /* no-op */ }
        }
      },

      abandonRun: () => {
        try { localStorage.removeItem(RUN_KEY); } catch { /* no-op */ }
        set({
          mode: null, seed: null, board: emptyBoard(),
          nextBubble: null, queuedBubble: null, drawCount: 0,
          shotsUsed: 0, score: 0,
          startedAt: 0, timeMs: 0, paused: false,
          solved: false, lost: false,
          par: null, dailyIso: null,
        });
        queue = null;
      },

      loadFromSave: (blob) => {
        const seed = blob.seed ?? Math.floor(Math.random() * 0xffffffff);
        const rng = deterministicRng(seed);
        let preset: DifficultyPreset;
        if (blob.mode === 'daily') {
          const iso = blob.dailyIso ?? new Date().toISOString().slice(0, 10);
          const cfg = dailyDifficulty(new Date(iso));
          const baseMode = cfg.mode as 'beginner' | 'intermediate' | 'expert';
          preset = { ...DIFFICULTY[baseMode], pityMax: blob.pityMax };
        } else {
          preset = DIFFICULTY[blob.mode as 'beginner' | 'intermediate' | 'expert'];
        }
        queue = makeQueue({ rng, difficulty: preset, boardSnapshot: () => get().board });
        // makeQueue() calls pick() once internally (drawCount=1). Fast-forward to blob.drawCount.
        for (let i = 0; i < blob.drawCount - 1; i++) queue.next();
        const board = makeBoard(blob.cells, {
          rows: blob.rows, cols: blob.cols, tileDiameter: blob.tileDiameter,
          pityRemaining: blob.pityRemaining, pityMax: blob.pityMax,
        });
        set({
          mode: blob.mode, seed,
          board,
          nextBubble: blob.nextBubble, queuedBubble: blob.queuedBubble, drawCount: blob.drawCount,
          shotsUsed: blob.shotsUsed, score: blob.score,
          startedAt: blob.startedAt, timeMs: blob.timeMs, paused: false,
          solved: false, lost: false,
          par: blob.par, dailyIso: blob.dailyIso,
        });
      },
    },
  };
});

function isoDate(d: Date): string { return d.toISOString().slice(0, 10); }

export function _parseSave(raw: string): SerializedSave | null {
  try {
    const blob = JSON.parse(raw) as SerializedSave;
    if (blob?.v !== 1) {
      try { localStorage.removeItem(RUN_KEY); } catch { /* no-op */ }
      return null;
    }
    return blob;
  } catch { return null; }
}

export function _forcePersist(): void {
  persist(useStore.getState());
}

let persistTimer: ReturnType<typeof setTimeout> | null = null;
function debouncePersist() {
  if (persistTimer) clearTimeout(persistTimer);
  persistTimer = setTimeout(() => {
    const s = useStore.getState();
    persist(s);
  }, 400);
}

function persist(s: RunState) {
  if (!s.mode || s.solved || s.lost) return;
  const blob: SerializedSave = {
    v: 1,
    mode: s.mode, seed: s.seed,
    cells: Array.from(s.board.cells),
    rows: s.board.rows, cols: s.board.cols, tileDiameter: s.board.tileDiameter,
    pityRemaining: s.board.pityRemaining, pityMax: s.board.pityMax,
    nextBubble: s.nextBubble, queuedBubble: s.queuedBubble, drawCount: s.drawCount,
    shotsUsed: s.shotsUsed, score: s.score,
    startedAt: s.startedAt, timeMs: s.timeMs,
    par: s.par, dailyIso: s.dailyIso,
  };
  try { localStorage.setItem(RUN_KEY, JSON.stringify(blob)); } catch { /* no-op */ }
}

export const useRunState = () => useStore(useShallow(s => ({
  mode: s.mode, board: s.board, nextBubble: s.nextBubble, queuedBubble: s.queuedBubble,
  shotsUsed: s.shotsUsed, score: s.score, timeMs: s.timeMs, paused: s.paused,
  solved: s.solved, lost: s.lost, par: s.par, dailyIso: s.dailyIso,
  pityRemaining: s.board.pityRemaining, pityMax: s.board.pityMax,
})));
export const useRunActions = () => useStore(s => s.actions);

// Dev-only test hooks (safe in production — guarded by __playwright flag or DEV mode)
if (typeof window !== 'undefined') {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const win = window as any;
  const isDev = typeof import.meta !== 'undefined' && (import.meta as unknown as { env?: { DEV?: boolean } }).env?.DEV;
  if (isDev || win.__playwright) {
    win.__fizzpopStartBeginner = () => useStore.getState().actions.startRun({ mode: 'beginner', seed: 42 });
    win.__fizzpopStartDaily = () => useStore.getState().actions.startRun({ mode: 'daily', date: new Date() });
    win.__fizzpopFakeWin = () => {
      const s = useStore.getState();
      useStore.setState({
        board: { ...s.board, cells: Object.freeze(new Array(s.board.rows * s.board.cols).fill(null)) },
        solved: true,
      });
    };
    win.__fizzpopTestState = () => ({
      shotsUsed: useStore.getState().shotsUsed,
      nextBubble: useStore.getState().nextBubble,
      queuedBubble: useStore.getState().queuedBubble,
      mode: useStore.getState().mode,
      score: useStore.getState().score,
    });
  }
}
