import { useEffect } from 'react';
import { useRunActions } from '../../state/store.js';
import { useStreakState } from '../../state/streak-store.js';
import { ModeCard } from './ModeCard.js';
import './mode-select.css';

export function ModeSelect() {
  const actions = useRunActions();
  const streak = useStreakState();

  // Keyboard shortcuts — only when mode-select is visible
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (document.activeElement instanceof HTMLInputElement) return;
      if (document.activeElement instanceof HTMLTextAreaElement) return;
      switch (e.key.toLowerCase()) {
        case '1': actions.startRun({ mode: 'beginner' }); break;
        case '2': actions.startRun({ mode: 'intermediate' }); break;
        case '3': actions.startRun({ mode: 'expert' }); break;
        case 'd': actions.startRun({ mode: 'daily', date: new Date() }); break;
      }
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [actions]);

  const todayIso = new Date().toISOString().slice(0, 10);
  const dailyDoneToday = streak.completed.includes(todayIso);
  const dailyBestToday = streak.bestByMode.daily?.[todayIso];

  return (
    <div className="fp-mode-select" role="region" aria-label="Choose a mode">
      <ModeCard
        title="Daily"
        kbd="D"
        description="Today's solver-validated puzzle."
        meta={dailyDoneToday && dailyBestToday != null
          ? `✓ Solved (${dailyBestToday} shots)`
          : `🔥 ${streak.current}-day streak`}
        onClick={() => actions.startRun({ mode: 'daily', date: new Date() })}
      />
      <ModeCard
        title="Beginner"
        kbd="1"
        description="4 colors · forgiving pity timer."
        meta={`Best ${(streak.bestByMode.beginner ?? 0).toLocaleString()}`}
        onClick={() => actions.startRun({ mode: 'beginner' })}
      />
      <ModeCard
        title="Intermediate"
        kbd="2"
        description="5 colors · default difficulty."
        meta={`Best ${(streak.bestByMode.intermediate ?? 0).toLocaleString()}`}
        onClick={() => actions.startRun({ mode: 'intermediate' })}
      />
      <ModeCard
        title="Expert"
        kbd="3"
        description="7 colors · weighted queue · long sessions."
        meta={`Best ${(streak.bestByMode.expert ?? 0).toLocaleString()}`}
        onClick={() => actions.startRun({ mode: 'expert' })}
      />
    </div>
  );
}
