import { useEffect, type ReactNode } from 'react';
import { useStore } from '../state/store.js';
import { useVisibilityPause } from '@bilkobibitkov/host-kit';

export function EngineSlot({ children }: { children: ReactNode }) {
  // 1s timer; only ticks when not paused/solved/lost
  useEffect(() => {
    const id = setInterval(() => {
      const s = useStore.getState();
      if (s.paused || s.solved || s.lost || !s.mode) return;
      useStore.setState({ timeMs: s.timeMs + 1000 });
    }, 1000);
    return () => clearInterval(id);
  }, []);

  // Pause on tab hidden via host-kit hook
  useVisibilityPause(
    () => useStore.getState().actions.pause(true),
    () => useStore.getState().actions.pause(false),
  );

  return <>{children}</>;
}
