import { useRunActions } from '../../state/store.js';
import type { Mode } from '../../engine/index.js';

interface Props {
  mode: Mode;
  won: boolean;
}

function capitalize(s: string): string {
  return s ? (s[0]?.toUpperCase() ?? '') + s.slice(1) : s;
}

export function PlayAgain({ mode, won }: Props) {
  const actions = useRunActions();
  return (
    <div className="fp-play-again" role="dialog" aria-label={won ? 'You won' : 'Game over'}>
      <h2>{won ? '🫧 Cleared!' : '💧 Game over'}</h2>
      <button
        className="fp-mode-card primary"
        onClick={() => actions.startRun({ mode })}
      >
        New {capitalize(mode ?? '')} run
      </button>
      <button
        className="fp-mode-card"
        onClick={() => actions.abandonRun()}
      >
        Change mode
      </button>
    </div>
  );
}
