// Animation loop for canvas-based FizzPop animations.
// Time complexity: O(jobs) per frame, jobs is bounded by max bubbles on board (~112).
// Enqueues jobs from bus events; draws and prunes on each RAF tick.

import { bus } from '../../lib/bus.js';
import type { Coord } from '../../lib/bus.js';

export interface AnimJob {
  kind: 'snap-flash' | 'pop' | 'drop' | 'row-shift';
  startedAt: number;
  duration: number;
  cells?: Coord[];
  color?: string;
}

const SQRT3_2 = Math.sqrt(3) / 2;
const TILE_DIAMETER = 64;

function isReduced(): boolean {
  if (document.documentElement.dataset.motion === 'reduce') return true;
  return matchMedia('(prefers-reduced-motion: reduce)').matches;
}

function colorFor(slot: unknown): string {
  const cs = getComputedStyle(document.documentElement);
  if (slot === 'rainbow') return '#cccccc';
  if (typeof slot === 'number' && slot >= 1 && slot <= 7) {
    return cs.getPropertyValue(`--bubble-${slot}`).trim() || '#888';
  }
  return '#888';
}

function cellCenter(cell: Coord): { x: number; y: number } {
  const x = cell.col * TILE_DIAMETER + (cell.row % 2 ? TILE_DIAMETER / 2 : 0) + TILE_DIAMETER / 2;
  const y = cell.row * TILE_DIAMETER * SQRT3_2 + TILE_DIAMETER / 2;
  return { x, y };
}

function drawJob(
  ctx: CanvasRenderingContext2D,
  job: AnimJob,
  t: number,
  _w: number,
  h: number,
): void {
  switch (job.kind) {
    case 'snap-flash': {
      const cell = job.cells?.[0];
      if (!cell) break;
      const { x, y } = cellCenter(cell);
      const r = (TILE_DIAMETER / 2) * (0.5 + t * 0.8);
      ctx.save();
      ctx.globalAlpha = 0.6 * (1 - t);
      ctx.strokeStyle = job.color ?? '#ffffff';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.stroke();
      ctx.restore();
      break;
    }
    case 'pop': {
      const cell = job.cells?.[0];
      if (!cell) break;
      const { x, y } = cellCenter(cell);
      const scale = t < 0.3 ? 1 + (t / 0.3) * 0.2 : 1.2 * (1 - (t - 0.3) / 0.7);
      const alpha = t < 0.3 ? 1 : 1 - (t - 0.3) / 0.7;
      ctx.save();
      ctx.globalAlpha = Math.max(0, alpha);
      ctx.fillStyle = job.color ?? '#888';
      ctx.beginPath();
      ctx.arc(x, y, (TILE_DIAMETER / 2 - 2) * Math.max(0, scale), 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
      break;
    }
    case 'drop': {
      const cell = job.cells?.[0];
      if (!cell) break;
      const { x, y: y0 } = cellCenter(cell);
      const dy = 0.5 * (h - y0) * (t * t) * 1.2;
      ctx.save();
      ctx.globalAlpha = Math.max(0, 1 - t);
      ctx.fillStyle = job.color ?? '#888';
      ctx.beginPath();
      ctx.arc(x, y0 + dy, TILE_DIAMETER / 2 - 2, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
      break;
    }
    case 'row-shift': {
      // Show a subtle downward arrow at the top-center for the duration.
      const { canvas } = ctx;
      const w = canvas.width / (window.devicePixelRatio || 1);
      ctx.save();
      ctx.globalAlpha = 0.5 * (1 - t);
      ctx.fillStyle = '#888888';
      ctx.font = '20px system-ui';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'top';
      ctx.fillText('↓', w / 2, 8);
      ctx.restore();
      break;
    }
  }
}

export function startAnimLoop(canvas: HTMLCanvasElement): () => void {
  const ctx2d = canvas.getContext('2d');
  if (!ctx2d) return () => { /* no-op */ };
  const ctx: CanvasRenderingContext2D = ctx2d;

  // Pre-allocated job pool; max 200 concurrent animations (112 cells × 2 types + overhead)
  const jobs: AnimJob[] = [];
  let raf = 0;
  let stopped = false;

  const offs = [
    bus.on('bubbleSnapped', ({ cell, color }) => {
      if (isReduced()) return;
      jobs.push({ kind: 'snap-flash', startedAt: performance.now(), duration: 120, cells: [cell], color: colorFor(color) });
    }),
    bus.on('clusterPopped', ({ cells, color }) => {
      if (isReduced()) return;
      const stagger = Math.min(30, 240 / Math.max(1, cells.length));
      cells.forEach((c, i) => {
        jobs.push({
          kind: 'pop',
          startedAt: performance.now() + i * stagger,
          duration: 220,
          cells: [c],
          color: colorFor(color),
        });
      });
    }),
    bus.on('floatersDropped', ({ cells }) => {
      if (isReduced()) return;
      cells.forEach((c) => {
        jobs.push({ kind: 'drop', startedAt: performance.now(), duration: 400, cells: [c] });
      });
    }),
    bus.on('rowAdded', () => {
      if (isReduced()) return;
      jobs.push({ kind: 'row-shift', startedAt: performance.now(), duration: 320 });
    }),
  ];

  function tick() {
    if (stopped) return;
    const dpr = window.devicePixelRatio || 1;
    const w = canvas.clientWidth;
    const h = canvas.clientHeight;
    if (canvas.width !== Math.round(w * dpr) || canvas.height !== Math.round(h * dpr)) {
      canvas.width = Math.round(w * dpr);
      canvas.height = Math.round(h * dpr);
    }
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, w, h);

    const now = performance.now();
    for (let i = jobs.length - 1; i >= 0; i--) {
      const job = jobs[i];
      if (!job) continue;
      const t = (now - job.startedAt) / job.duration;
      if (t < 0) continue;
      if (t >= 1) { jobs.splice(i, 1); continue; }
      drawJob(ctx, job, t, w, h);
    }

    raf = requestAnimationFrame(tick);
  }

  raf = requestAnimationFrame(tick);

  return () => {
    stopped = true;
    cancelAnimationFrame(raf);
    offs.forEach((off) => off());
  };
}
