import { useState } from 'react';
import { useRunState } from '../../state/store.js';
import { bus } from '../../lib/bus.js';
import { PityRing } from './PityRing.js';
import { QueuePreview } from './QueuePreview.js';
import './hud.css';

function capitalize(s: string): string {
  return s ? (s[0]?.toUpperCase() ?? '') + s.slice(1) : s;
}

export function Hud() {
  const s = useRunState();
  const [confirmOpen, setConfirmOpen] = useState(false);

  const min = Math.floor(s.timeMs / 60000);
  const sec = Math.floor((s.timeMs % 60000) / 1000);
  const time = `${String(min).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;

  const isDaily = s.mode === 'daily';
  const modeLabel = isDaily
    ? `Daily · ${new Date(s.dailyIso ?? '').toLocaleDateString(undefined, { weekday: 'short' })}`
    : capitalize(s.mode ?? '');

  function onRestart() {
    if (isDaily) setConfirmOpen(true);
    else bus.emit('restartRequested', {});
  }

  function confirmRestart() {
    bus.emit('restartRequested', {});
    setConfirmOpen(false);
  }

  return (
    <div className="fp-hud" role="region" aria-label="Game status">
      <div className="fp-hud-left">
        <span className="fp-hud-mode">{modeLabel}</span>
        <span className="fp-hud-sep">·</span>
        <span
          className="fp-hud-time"
          aria-label={`Elapsed time ${min} minutes ${sec} seconds`}
        >
          {time}
        </span>
      </div>

      <div className="fp-hud-mid" aria-live="polite">
        {isDaily
          ? <span>Shots: {s.shotsUsed}{s.par != null ? ` / ${s.par}` : ''}</span>
          : <span>Score {s.score.toLocaleString()}</span>
        }
      </div>

      <div className="fp-hud-right">
        <QueuePreview slot={s.queuedBubble} />
        <PityRing remaining={s.pityRemaining} max={s.pityMax} />
        <button
          className="fp-hud-btn"
          aria-label="Settings"
          onClick={() => bus.emit('settingsOpened', {})}
        >
          ⚙
        </button>
        <button
          className="fp-hud-btn"
          aria-label="Restart current run"
          onClick={onRestart}
        >
          ↺
        </button>
      </div>

      {confirmOpen && (
        <div className="fp-confirm" role="dialog" aria-label="Restart today's puzzle">
          <p>Restart today's puzzle? This won't affect your streak.</p>
          <button onClick={confirmRestart}>Restart</button>
          <button onClick={() => setConfirmOpen(false)}>Cancel</button>
        </div>
      )}
    </div>
  );
}
