interface Props {
  title: string;
  kbd: string;
  description: string;
  meta: string;
  onClick: () => void;
}

export function ModeCard({ title, kbd, description, meta, onClick }: Props) {
  return (
    <button
      className="fp-mode-card"
      onClick={onClick}
      aria-label={`${title}. ${description}. ${meta}. Press ${kbd} for shortcut.`}
    >
      <span className="fp-mode-kbd" aria-hidden="true">{kbd}</span>
      <h3 className="fp-mode-title">{title}</h3>
      <p className="fp-mode-desc">{description}</p>
      <p className="fp-mode-meta">{meta}</p>
    </button>
  );
}
