import { useState } from 'react';
import { useRunState } from '../../state/store.js';
import { useStreakState } from '../../state/streak-store.js';
import { isoDate } from './daily-loader.js';

function capitalize(s: string): string {
  return s ? (s[0]?.toUpperCase() ?? '') + s.slice(1) : s;
}

export function ShareTile({ onDismiss }: { onDismiss: () => void }) {
  const run = useRunState();
  const streak = useStreakState();
  const [copied, setCopied] = useState(false);

  function build(): string {
    const min = Math.floor(run.timeMs / 60000);
    const sec = Math.floor((run.timeMs % 60000) / 1000);
    const today = isoDate(new Date());
    const date = new Date().toLocaleDateString(undefined, { weekday: 'short', month: 'numeric', day: 'numeric' });
    return [
      `Bilko FizzPop · ${date} · ${capitalize(run.mode ?? 'Daily')}`,
      `\u{1FAE7} ${run.shotsUsed}${run.par != null ? `/${run.par}` : ''} shots  ⏱ ${min}:${String(sec).padStart(2, '0')}`,
      `🔥 streak ${streak.current}`,
      `bilko.run/projects/fizzpop/?d=${today}`,
    ].join('\n');
  }

  async function share() {
    const text = build();
    const nav = navigator as Navigator & { share?: (data: { text: string }) => Promise<void> };
    if (nav.share) {
      try { await nav.share({ text }); onDismiss(); return; } catch { /* fall through */ }
    }
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(onDismiss, 1500);
    } catch { /* no-op */ }
  }

  return (
    <button className="fp-share-btn" onClick={() => void share()}>
      {copied ? 'Copied!' : 'Share'}
    </button>
  );
}
