import { createBus } from '@bilkobibitkov/host-kit';

export type BubbleColor = 1 | 2 | 3 | 4 | 5 | 6 | 7 | 'rainbow';
export type Coord = { row: number; col: number };
export type Vec2 = { x: number; y: number };

export type FizzPopEvents = {
  // Input
  aimUpdated: { angleDeg: number };
  fireRequested: { _?: never };
  swapRequested: { _?: never };
  restartRequested: { _?: never };

  // Engine output
  bubbleFired: { color: BubbleColor; angleDeg: number; startedAtMs: number };
  bubbleSnapped: { color: BubbleColor; cell: Coord };
  clusterPopped: { cells: Coord[]; color: BubbleColor; size: number };
  floatersDropped: { cells: Coord[]; count: number };
  rowAdded: { reason: 'pity' | 'manual' };
  pityChanged: { remaining: number; max: number };

  // Game state
  gameStarted: { mode: 'daily' | 'beginner' | 'intermediate' | 'expert'; seed: number };
  gameWon: { mode: string; shotsUsed: number; par?: number; score: number; timeMs: number };
  gameLost: { mode: string; shotsUsed: number; score: number; timeMs: number };
  modeSelected: { mode: 'daily' | 'beginner' | 'intermediate' | 'expert' };
  dailyDateChanged: { iso: string };

  // UI
  settingsOpened: { _?: never };
  settingsClosed: { _?: never };
};

export const bus = createBus<FizzPopEvents>();
