export interface Vec2 { x: number; y: number }

/**
 * Compute aim angle (degrees) from a pointer position in board-logical coordinates.
 * Cannon pivot is at (cols*td/2, rows*rowHeight+32). Returns angle in (0,180].
 * Pointer below the pivot clamps to 8° (rightward) or 172° (leftward).
 */
export function angleFromPointer(
  boardPos: Vec2,
  board: { cols: number; rows: number; tileDiameter: number },
): number {
  const SQRT3_2 = Math.sqrt(3) / 2;
  const cannonX = (board.cols * board.tileDiameter) / 2;
  const cannonY = board.rows * board.tileDiameter * SQRT3_2 + 32;
  const dx = boardPos.x - cannonX;
  const dy = cannonY - boardPos.y; // positive = above cannon (upward in screen)
  if (dy <= 0) return dx >= 0 ? 8 : 172;
  return Math.atan2(dy, dx) * 180 / Math.PI;
}

export interface KeyboardOpts {
  getAngle: () => number;
  setAngle: (a: number) => void;
  fire: () => void;
  swap: () => void;
  restart: () => void;
  toggleHints: () => void;
}

export function attachKeyboard(opts: KeyboardOpts): () => void {
  const held = new Set<string>();
  let raf = 0;

  function tick() {
    if (held.has('ArrowLeft'))  opts.setAngle(opts.getAngle() + 0.8);
    if (held.has('ArrowRight')) opts.setAngle(opts.getAngle() - 0.8);
    raf = requestAnimationFrame(tick);
  }

  function onKey(e: KeyboardEvent) {
    const tag = (e.target as HTMLElement)?.tagName;
    if (tag === 'INPUT' || tag === 'TEXTAREA') return;
    if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
      e.preventDefault();
      if (!held.has(e.key)) {
        held.add(e.key);
        opts.setAngle(opts.getAngle() + (e.key === 'ArrowLeft' ? 4 : -4));
      }
    } else if (e.key === ' ' || e.code === 'Space') {
      e.preventDefault();
      opts.fire();
    } else if (e.key === 's' || e.key === 'S') {
      e.preventDefault();
      opts.swap();
    } else if (e.key === 'r' || e.key === 'R') {
      e.preventDefault();
      opts.restart();
    } else if (e.key === '?') {
      e.preventDefault();
      opts.toggleHints();
    }
  }

  function onUp(e: KeyboardEvent) { held.delete(e.key); }

  window.addEventListener('keydown', onKey);
  window.addEventListener('keyup', onUp);
  raf = requestAnimationFrame(tick);

  return () => {
    window.removeEventListener('keydown', onKey);
    window.removeEventListener('keyup', onUp);
    cancelAnimationFrame(raf);
  };
}
