import { create } from 'zustand';
import { useShallow } from 'zustand/react/shallow';

const KEY = 'bilko_fizzpop_streak_v1';

export interface StreakState {
  v: 1;
  current: number;
  longest: number;
  freezes: number;
  lastWinDate: string | null;
  completed: string[];
  bestByMode: {
    daily?: Record<string, number>;
    beginner?: number;
    intermediate?: number;
    expert?: number;
  };
}

const empty: StreakState = {
  v: 1, current: 0, longest: 0, freezes: 0,
  lastWinDate: null, completed: [], bestByMode: {},
};

function load(): StreakState {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return empty;
    const parsed = JSON.parse(raw);
    if (parsed?.v !== 1) return empty;
    return parsed as StreakState;
  } catch { return empty; }
}

function save(s: StreakState) {
  try { localStorage.setItem(KEY, JSON.stringify(s)); } catch { /* no-op */ }
}

function daysBetween(a: string, b: string): number {
  return Math.round((Date.parse(b) - Date.parse(a)) / 86_400_000);
}

interface Actions {
  recordDailyWin: (isoDate: string, shotsUsed: number) => void;
  recordEndlessScore: (mode: 'beginner' | 'intermediate' | 'expert', score: number) => void;
}

export const useStreakStore = create<StreakState & { actions: Actions }>((set, get) => ({
  ...load(),
  actions: {
    recordDailyWin: (date, shotsUsed) => {
      const s = get();
      if (s.completed.includes(date)) return;
      const completed = [...s.completed, date].sort();
      let current = s.current;
      let freezes = s.freezes;
      if (s.lastWinDate) {
        const gap = daysBetween(s.lastWinDate, date);
        if (gap === 1) {
          current += 1;
        } else if (gap > 1) {
          const missed = gap - 1;
          const used = Math.min(missed, freezes);
          freezes -= used;
          if (used >= missed) current += 1;
          else current = 1;
        }
      } else {
        current = 1;
      }
      // Every 7 wins earns 1 freeze (max 3 stockpiled)
      if (completed.length % 7 === 0 && freezes < 3) freezes += 1;
      const bestForDay = s.bestByMode.daily?.[date];
      const bestByMode = {
        ...s.bestByMode,
        daily: {
          ...(s.bestByMode.daily ?? {}),
          [date]: bestForDay == null ? shotsUsed : Math.min(bestForDay, shotsUsed),
        },
      };
      const next: StreakState = {
        v: 1, current, longest: Math.max(s.longest, current), freezes,
        lastWinDate: date, completed, bestByMode,
      };
      set({ ...next, actions: s.actions });
      save(next);
    },

    recordEndlessScore: (mode, score) => {
      const s = get();
      const cur = s.bestByMode[mode] ?? 0;
      if (score <= cur) return;
      const bestByMode = { ...s.bestByMode, [mode]: score };
      set({ bestByMode });
      save({ ...s, bestByMode });
    },
  },
}));

export const useStreakState = () => useStreakStore(useShallow(s => ({
  current: s.current, longest: s.longest, freezes: s.freezes,
  lastWinDate: s.lastWinDate, completed: s.completed, bestByMode: s.bestByMode,
})));
export const useStreakActions = () => useStreakStore(s => s.actions);
