interface Props { remaining: number; max: number }

export function PityRing({ remaining, max }: Props) {
  const r = 9;
  const circumference = 2 * Math.PI * r;
  const filled = Math.max(0, Math.min(1, remaining / Math.max(1, max)));
  const danger = remaining === 1;
  return (
    <svg
      width="24"
      height="24"
      viewBox="0 0 24 24"
      role="img"
      aria-label={`Pity timer: ${remaining} of ${max} shots before next row drop`}
      className={`fp-pity-ring${danger ? ' danger' : ''}`}
    >
      <circle
        cx="12" cy="12" r={r}
        fill="none"
        stroke="currentColor"
        strokeOpacity="0.15"
        strokeWidth="3"
      />
      <circle
        cx="12" cy="12" r={r}
        fill="none"
        stroke={danger ? 'var(--conflict)' : 'var(--entered, #34c759)'}
        strokeWidth="3"
        strokeLinecap="round"
        strokeDasharray={`${circumference * filled} ${circumference}`}
        transform="rotate(-90 12 12)"
      />
    </svg>
  );
}
