const SHORTCUTS: { key: string; description: string }[] = [
  { key: '←/→', description: 'Aim cannon' },
  { key: 'Space', description: 'Fire' },
  { key: 'S', description: 'Swap with queue' },
  { key: 'R', description: 'Restart current run' },
  { key: '1', description: 'Beginner (mode-select)' },
  { key: '2', description: 'Intermediate (mode-select)' },
  { key: '3', description: 'Expert (mode-select)' },
  { key: 'D', description: 'Daily (mode-select)' },
  { key: 'Esc', description: 'Close settings' },
];

export function KeyboardHelp() {
  return (
    <dl className="fp-kbd-help">
      {SHORTCUTS.map((s) => (
        <div key={s.key} className="fp-kbd-row">
          <dt><kbd>{s.key}</kbd></dt>
          <dd>{s.description}</dd>
        </div>
      ))}
    </dl>
  );
}
