export type ThemeChoice = 'light' | 'dark' | 'system';

const KEY = 'bilko_fizzpop_theme_v1';
const CB_KEY = 'bilko_fizzpop_cb_v1';
const MOTION_KEY = 'bilko_fizzpop_motion_v1';

export function getTheme(): ThemeChoice {
  try {
    const v = localStorage.getItem(KEY);
    return v === 'light' || v === 'dark' ? v : 'system';
  } catch { return 'system'; }
}

export function setTheme(c: ThemeChoice): void {
  if (c === 'system') {
    delete document.documentElement.dataset.theme;
    try { localStorage.removeItem(KEY); } catch { /* no-op */ }
  } else {
    document.documentElement.dataset.theme = c;
    try { localStorage.setItem(KEY, c); } catch { /* no-op */ }
  }
}

export function getColorBlind(): boolean {
  try { return localStorage.getItem(CB_KEY) === '1'; } catch { return false; }
}

export function setColorBlind(on: boolean): void {
  if (on) {
    document.documentElement.dataset.cb = '1';
    try { localStorage.setItem(CB_KEY, '1'); } catch { /* no-op */ }
  } else {
    delete document.documentElement.dataset.cb;
    try { localStorage.removeItem(CB_KEY); } catch { /* no-op */ }
  }
}

export function getMotionOverride(): boolean {
  try { return localStorage.getItem(MOTION_KEY) === '1'; } catch { return false; }
}

export function setMotionOverride(on: boolean): void {
  if (on) {
    document.documentElement.dataset.motion = 'reduce';
    try { localStorage.setItem(MOTION_KEY, '1'); } catch { /* no-op */ }
  } else {
    delete document.documentElement.dataset.motion;
    try { localStorage.removeItem(MOTION_KEY); } catch { /* no-op */ }
  }
}

/** Apply persisted theme preferences on startup (call before first render). */
export function applyStoredTheme(): void {
  const t = getTheme();
  if (t !== 'system') document.documentElement.dataset.theme = t;
  if (getColorBlind()) document.documentElement.dataset.cb = '1';
  if (getMotionOverride()) document.documentElement.dataset.motion = 'reduce';
}
