import type { Board, BubbleSlot, Vec2 } from '../../engine/index.js';

export interface BubbleColors {
  bubbles: string[];   // index 0..6 = colors 1..7
  ink: string;
  paper: string;
  conflict: string;
}

export interface RenderState {
  board: Board;
  tileDiameter: number;
  angleDeg: number;
  nextBubble: BubbleSlot;
  inFlight: { pos: Vec2; color: BubbleSlot } | null;
  colors: BubbleColors;
  width: number;
  height: number;
}

const SQRT3_2 = Math.sqrt(3) / 2;

const GLYPHS = ['●', '◆', '▲', '■', '✚', '★', '◐'];

export function renderFrame(ctx: CanvasRenderingContext2D, s: RenderState): void {
  ctx.clearRect(0, 0, s.width, s.height);
  // Background
  ctx.fillStyle = s.colors.paper;
  ctx.fillRect(0, 0, s.width, s.height);
  // Board bubbles
  drawBoard(ctx, s);
  // Game-over line
  drawGameOverLine(ctx, s);
  // Aim line (drawn behind in-flight bubble)
  if (!s.inFlight) {
    drawAimLine(ctx, s);
  }
  // In-flight bubble (above grid)
  if (s.inFlight && s.inFlight.color !== null) {
    drawBubble(ctx, s.inFlight.pos.x, s.inFlight.pos.y, s.tileDiameter / 2 - 2, s.inFlight.color, s.colors);
  }
}

function drawBoard(ctx: CanvasRenderingContext2D, s: RenderState): void {
  const radius = s.tileDiameter / 2 - 2;
  for (let row = 0; row < s.board.rows; row++) {
    for (let col = 0; col < s.board.cols; col++) {
      const cell = s.board.cells[row * s.board.cols + col] ?? null;
      if (cell === null) continue;
      const x = col * s.tileDiameter + (row % 2 ? s.tileDiameter / 2 : 0) + s.tileDiameter / 2;
      const y = row * s.tileDiameter * SQRT3_2 + s.tileDiameter / 2;
      drawBubble(ctx, x, y, radius, cell, s.colors);
    }
  }
}

export function drawBubble(ctx: CanvasRenderingContext2D, x: number, y: number, r: number, slot: BubbleSlot, colors: BubbleColors): void {
  const color = slot === 'rainbow' ? '#cccccc' : (colors.bubbles[(slot as number) - 1] ?? '#888888');
  // Radial gradient body (top-left highlight, mid body, bottom shadow)
  const grad = ctx.createRadialGradient(x - r * 0.3, y - r * 0.3, r * 0.1, x, y, r);
  grad.addColorStop(0, lighten(color, 0.4));
  grad.addColorStop(0.6, color);
  grad.addColorStop(1, darken(color, 0.2));
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(x, y, r, 0, Math.PI * 2);
  ctx.fill();
  // Inner stroke
  ctx.strokeStyle = darken(color, 0.3);
  ctx.lineWidth = 1;
  ctx.stroke();
  // Glyph centered
  ctx.fillStyle = colors.paper;
  ctx.font = `${Math.floor(r * 0.9)}px system-ui, -apple-system, sans-serif`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  const glyph = slot === 'rainbow' ? '◇' : (GLYPHS[(slot as number) - 1] ?? '·');
  ctx.fillText(glyph, x, y);
}

function drawAimLine(ctx: CanvasRenderingContext2D, s: RenderState): void {
  if (s.nextBubble === null) return;
  const startX = (s.board.cols * s.tileDiameter) / 2;
  const startY = s.board.rows * s.tileDiameter * SQRT3_2 + 32;
  // Angle convention: 90 = straight up (standard math)
  const a = s.angleDeg * Math.PI / 180;
  const vx = Math.cos(a);
  const vy = -Math.sin(a);     // y decreasing = upward in screen coords
  const maxWall = s.board.cols * s.tileDiameter;
  let x = startX;
  let y = startY;
  ctx.save();
  ctx.setLineDash([4, 6]);
  ctx.lineWidth = 8;
  const colorIdx = s.nextBubble === 'rainbow' ? -1 : (s.nextBubble as number) - 1;
  const bubbleColor = colorIdx < 0 ? '#cccccc' : (s.colors.bubbles[colorIdx] ?? '#888888');
  ctx.strokeStyle = bubbleColor + '88'; // 53% opacity
  ctx.beginPath();
  ctx.moveTo(x, y);
  // Step until first wall or top (up to 1200 px)
  for (let step = 0; step < 1200; step++) {
    x += vx;
    y += vy;
    if (x < 8 || x > maxWall - 8) break; // first wall contact
    if (y < 8) break;                     // top of playfield
  }
  ctx.lineTo(x, y);
  ctx.stroke();
  ctx.restore();
}

function drawGameOverLine(ctx: CanvasRenderingContext2D, s: RenderState): void {
  const y = (s.board.rows - 1) * s.tileDiameter * SQRT3_2;
  ctx.save();
  ctx.setLineDash([6, 4]);
  ctx.strokeStyle = s.colors.conflict + '4d'; // 30% opacity
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(0, y);
  ctx.lineTo(s.width, y);
  ctx.stroke();
  ctx.restore();
}

function lighten(hex: string, amount: number): string {
  return mix(hex, '#ffffff', amount);
}

function darken(hex: string, amount: number): string {
  return mix(hex, '#000000', amount);
}

function mix(a: string, b: string, t: number): string {
  const pa = parseHex(a);
  const pb = parseHex(b);
  return `rgb(${Math.round(pa[0] * (1 - t) + pb[0] * t)},${Math.round(pa[1] * (1 - t) + pb[1] * t)},${Math.round(pa[2] * (1 - t) + pb[2] * t)})`;
}

function parseHex(h: string): [number, number, number] {
  const m = h.replace('#', '');
  const full = m.length === 3 ? m.split('').map(c => c + c).join('') : m;
  const v = parseInt(full, 16);
  return [(v >> 16) & 255, (v >> 8) & 255, v & 255];
}
