import { useEffect, useRef } from 'react';
import { useStreakState } from '../../state/streak-store.js';
import { useRunActions } from '../../state/store.js';
import { isoDate } from './daily-loader.js';

function trapFocusInline(container: HTMLElement): () => void {
  const focusables = container.querySelectorAll<HTMLElement>(
    'button:not([disabled]), [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
  );
  const first = focusables[0];
  const last = focusables[focusables.length - 1];
  function onKey(e: KeyboardEvent) {
    if (e.key !== 'Tab' || focusables.length === 0) return;
    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault();
      last?.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault();
      first?.focus();
    }
  }
  container.addEventListener('keydown', onKey);
  first?.focus();
  return () => container.removeEventListener('keydown', onKey);
}

interface Props {
  onClose: () => void;
}

export function CalendarSheet({ onClose }: Props) {
  const streak = useStreakState();
  const actions = useRunActions();
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const release = trapFocusInline(el);
    function onEsc(e: KeyboardEvent) {
      if (e.key === 'Escape') onClose();
    }
    window.addEventListener('keydown', onEsc);
    return () => {
      window.removeEventListener('keydown', onEsc);
      release();
    };
  }, [onClose]);

  // Build last 90 days
  const today = new Date();
  const todayIso = isoDate(today);
  const days: Date[] = [];
  for (let i = 89; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    days.push(d);
  }

  function onDayClick(d: Date) {
    const iso = isoDate(d);
    if (iso > todayIso) return;
    actions.startRun({ mode: 'daily', date: d });
    onClose();
  }

  // Monday-based offset for first day
  const firstDay = days[0];
  const offset = firstDay ? ((firstDay.getDay() + 6) % 7) : 0;

  return (
    <div className="fp-cal-sheet" role="presentation" onClick={onClose}>
      <div
        ref={containerRef}
        role="dialog"
        aria-label="Daily puzzle calendar — last 90 days"
        aria-modal="true"
        className="fp-cal-grid"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Close button spans full width */}
        <div style={{ gridColumn: '1 / -1', display: 'flex', justifyContent: 'flex-end', marginBottom: 4 }}>
          <button
            className="fp-cal-close-btn"
            onClick={onClose}
            aria-label="Close calendar"
          >
            ✕
          </button>
        </div>

        {/* Day-of-week header: Mon–Sun */}
        {['M', 'T', 'W', 'T', 'F', 'S', 'S'].map((d, i) => (
          <div key={i} className="fp-cal-header">{d}</div>
        ))}

        {/* Padding cells for day-of-week alignment */}
        {Array.from({ length: offset }, (_, i) => <div key={`pad-${i}`} />)}

        {/* Day cells */}
        {days.map((d) => {
          const iso = isoDate(d);
          const isFuture = iso > todayIso;
          const completed = streak.completed.includes(iso);
          const best = streak.bestByMode.daily?.[iso];
          return (
            <button
              key={iso}
              className={`fp-cal-cell${completed ? ' completed' : ''}${isFuture ? ' future' : ''}`}
              onClick={() => { if (!isFuture) onDayClick(d); }}
              aria-label={`${iso}${completed ? `, solved in ${best ?? '?'} shots` : ''}${isFuture ? ', future date' : ''}`}
              aria-disabled={isFuture || undefined}
            >
              <span>{d.getDate()}</span>
              {completed && <span className="best">{best}</span>}
            </button>
          );
        })}
      </div>
    </div>
  );
}
