import playfieldsData from '../../data/daily-playfields.json' assert { type: 'json' };
import type { Board, BubbleSlot } from '../../engine/index.js';
import { emptyBoard, dailySeed, dailyDifficulty } from '../../engine/index.js';

interface PlayfieldRecord {
  id: number;
  difficultyHint: 'beginner' | 'intermediate' | 'expert';
  rows: (string | null)[][];
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const PLAYFIELDS: PlayfieldRecord[] = (playfieldsData as any).playfields;

export function dailyPlayfieldFor(date: Date): { board: Board; record: PlayfieldRecord } {
  const seed = dailySeed(date);
  const idx = seed % PLAYFIELDS.length;
  const record = PLAYFIELDS[idx] ?? PLAYFIELDS[0]!;
  const cells: BubbleSlot[] = [];
  for (let row = 0; row < 14; row++) {
    for (let col = 0; col < 8; col++) {
      const v = record.rows[row]?.[col];
      cells.push(v == null ? null : (parseInt(v, 10) as BubbleSlot));
    }
  }
  const cfg = dailyDifficulty(date);
  const base = emptyBoard({ rows: 14, cols: 8, tileDiameter: 64 });
  return {
    board: {
      ...base,
      cells: Object.freeze(cells),
      pityRemaining: cfg.pityMax,
      pityMax: cfg.pityMax,
    },
    record,
  };
}

export function isoDate(d: Date): string {
  return d.toISOString().slice(0, 10);
}

export function parseDateParam(): Date | null {
  if (typeof location === 'undefined') return null;
  const params = new URLSearchParams(location.search);
  const d = params.get('d');
  if (!d || !/^\d{4}-\d{2}-\d{2}$/.test(d)) return null;
  const parsed = new Date(d + 'T12:00:00Z');
  if (isNaN(parsed.getTime())) return null;
  return parsed;
}
