import { Board } from '../components/board/index.js';
import { useRunState } from '../state/store.js';

export function BoardSlot() {
  const s = useRunState();
  if (!s.mode) {
    // No active run; mode-select UI lives in the difficulty-modes PRD
    return (
      <div data-slot="board" style={{ padding: '24px', textAlign: 'center', color: 'var(--ink)', opacity: 0.6 }}>
        Pick a mode to start.
      </div>
    );
  }
  return <Board />;
}
