import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App.js';
import { initBusBridge } from './state/bus-bridge.js';
import { useStore } from './state/store.js';
import { bus } from './lib/bus.js';

initBusBridge();
useStore.getState().actions.resume();

if (typeof window !== 'undefined' && ((import.meta as any).env?.DEV || (window as any).__playwright)) {
  (window as any).__fizzpopBus = bus;
}

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <App />
  </StrictMode>,
);
