import type { BubbleSlot } from '../../engine/index.js';

const COLOR_VARS = [
  '--bubble-1', '--bubble-2', '--bubble-3', '--bubble-4',
  '--bubble-5', '--bubble-6', '--num-7',
];
const GLYPHS = ['●', '◆', '▲', '■', '✚', '★', '◐'];

export function QueuePreview({ slot }: { slot: BubbleSlot }) {
  if (slot === null) {
    return <span className="fp-queue-prev empty" aria-hidden="true" />;
  }
  const isRainbow = slot === 'rainbow';
  const idx = isRainbow ? -1 : (slot as number) - 1;
  const bg = isRainbow
    ? 'conic-gradient(red, orange, yellow, green, blue, indigo, violet, red)'
    : `var(${COLOR_VARS[idx] ?? '--bubble-1'})`;
  const glyph = isRainbow ? '◇' : (GLYPHS[idx] ?? '·');
  return (
    <span
      className="fp-queue-prev"
      role="img"
      style={{ background: bg }}
      aria-label={`Next: ${isRainbow ? 'rainbow' : `bubble color ${slot}`}`}
    >
      <span aria-hidden="true">{glyph}</span>
    </span>
  );
}
