import { ModeSelect, PlayAgain } from '../components/mode-select/index.js';
import { useRunState } from '../state/store.js';

export function DifficultySlot() {
  const s = useRunState();
  if (!s.mode) return <ModeSelect />;
  if (s.solved || s.lost) return <PlayAgain mode={s.mode} won={s.solved} />;
  return null;
}
