import { useEffect, useRef, useState } from 'react';
import { bus } from '../../lib/bus.js';
import {
  getTheme, setTheme, getColorBlind, setColorBlind,
  getMotionOverride, setMotionOverride, type ThemeChoice,
} from '../theme/theme.js';
import { trapFocus } from '../a11y/trap-focus.js';
import { KeyboardHelp } from './KeyboardHelp.js';
import './settings.css';

const HAPTICS_KEY = 'bilko_fizzpop_haptics_v1';
const SOUNDS_KEY = 'bilko_fizzpop_sounds_v1';

export function SettingsOverlay() {
  const [open, setOpen] = useState(false);
  const [t, setT] = useState<ThemeChoice>('system');
  const [cb, setCb] = useState(false);
  const [motion, setMotion] = useState(false);
  const [haptics, setHapticsState] = useState(true);
  const [sounds, setSoundsState] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  const openerRef = useRef<HTMLElement | null>(null);

  // Hydrate from localStorage on open (avoids SSR/test mismatch)
  useEffect(() => {
    if (!open) return;
    try {
      setT(getTheme());
      setCb(getColorBlind());
      setMotion(getMotionOverride());
      setHapticsState(localStorage.getItem(HAPTICS_KEY) !== '0');
      setSoundsState(localStorage.getItem(SOUNDS_KEY) === '1');
    } catch { /* no-op */ }
  }, [open]);

  // Subscribe to settingsOpened bus event
  useEffect(() => {
    return bus.on('settingsOpened', () => {
      openerRef.current = document.activeElement as HTMLElement | null;
      setOpen(true);
    });
  }, []);

  // Focus trap + escape handler
  useEffect(() => {
    if (!open || !ref.current) return;
    const release = trapFocus(ref.current, () => openerRef.current ?? undefined);
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') close();
    }
    window.addEventListener('keydown', onKey);
    return () => {
      window.removeEventListener('keydown', onKey);
      release();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  function close() {
    setOpen(false);
    bus.emit('settingsClosed', {});
  }

  function pickTheme(c: ThemeChoice) { setTheme(c); setT(c); }
  function toggleCb() { const n = !cb; setColorBlind(n); setCb(n); }
  function toggleMotion() { const n = !motion; setMotionOverride(n); setMotion(n); }
  function toggleHaptics() {
    const n = !haptics;
    try { localStorage.setItem(HAPTICS_KEY, n ? '1' : '0'); } catch { /* no-op */ }
    setHapticsState(n);
  }
  function toggleSounds() {
    const n = !sounds;
    try { localStorage.setItem(SOUNDS_KEY, n ? '1' : '0'); } catch { /* no-op */ }
    setSoundsState(n);
  }

  if (!open) return null;

  return (
    <div className="fp-settings-backdrop" role="presentation" onClick={close}>
      <div
        ref={ref}
        className="fp-settings-overlay"
        role="dialog"
        aria-label="Settings"
        aria-modal="true"
        onClick={(e) => e.stopPropagation()}
      >
        <header>
          <h2>Settings</h2>
          <button
            className="fp-settings-close"
            onClick={close}
            aria-label="Close settings"
          >
            ✕
          </button>
        </header>

        <section>
          <h3>Theme</h3>
          {(['light', 'dark', 'system'] as ThemeChoice[]).map((c) => (
            <label key={c} className={c === t ? 'on' : ''}>
              <input
                type="radio"
                name="fizzpop-theme"
                checked={c === t}
                onChange={() => pickTheme(c)}
              />
              <span style={{ textTransform: 'capitalize' }}>{c}</span>
            </label>
          ))}
        </section>

        <section>
          <h3>Accessibility</h3>
          <label>
            <input type="checkbox" checked={cb} onChange={toggleCb} />
            Color-blind safe palette
          </label>
          <label>
            <input type="checkbox" checked={motion} onChange={toggleMotion} />
            Always use reduced motion
          </label>
        </section>

        <section>
          <h3>Feedback</h3>
          <label>
            <input type="checkbox" checked={haptics} onChange={toggleHaptics} />
            Haptics (mobile)
          </label>
          <label>
            <input type="checkbox" checked={sounds} onChange={toggleSounds} />
            Sounds
          </label>
        </section>

        <section>
          <h3>Keyboard shortcuts</h3>
          <KeyboardHelp />
        </section>
      </div>
    </div>
  );
}
