import { bus } from '../lib/bus.js';
import { useStore } from './store.js';
import { useStreakStore } from './streak-store.js';

export function initBusBridge() {
  bus.on('fireRequested', () => {
    // Aim is held in the Board component; this handler reserved for gamepad/future coordination.
    // The Board component calls actions.recordShot directly on pointer/keyboard fire.
  });
  bus.on('swapRequested', () => useStore.getState().actions.swapQueue());
  bus.on('restartRequested', () => {
    const s = useStore.getState();
    if (!s.mode) return;
    s.actions.startRun({ mode: s.mode, seed: s.seed ?? undefined });
  });
  bus.on('gameWon', ({ mode, shotsUsed, score }) => {
    const s = useStore.getState();
    if (mode === 'daily' && s.dailyIso) {
      useStreakStore.getState().actions.recordDailyWin(s.dailyIso, shotsUsed);
    } else if (mode === 'beginner' || mode === 'intermediate' || mode === 'expert') {
      useStreakStore.getState().actions.recordEndlessScore(mode, score);
    }
  });
}
