import { useEffect, useLayoutEffect, useRef, useState } from 'react';
import { useRunState, useRunActions } from '../../state/store.js';
import { simulateShot, aim, type ShotResult, type BubbleSlot } from '../../engine/index.js';
import { bus } from '../../lib/bus.js';
import { renderFrame, type RenderState } from './render.js';
import { angleFromPointer, attachKeyboard } from './input.js';
import { readBubbleColors, type BubbleColors } from './colors.js';
import { AnimLayer } from '../../features/anim/index.js';
import './board.css';

const SQRT3_2 = Math.sqrt(3) / 2;
const GLYPHS = ['●', '◆', '▲', '■', '✚', '★', '◐'];

function glyphFor(b: unknown): string {
  if (typeof b === 'number' && b >= 1 && b <= 7) return GLYPHS[b - 1] ?? '·';
  if (b === 'rainbow') return '◇';
  return '·';
}

function describeBubble(b: unknown): string {
  const names: Record<string, string> = {
    '1': 'blue', '2': 'red', '3': 'green', '4': 'amber',
    '5': 'violet', '6': 'pink', '7': 'dark', 'rainbow': 'rainbow',
  };
  return names[String(b)] ?? 'empty';
}

interface AnimState { shot: ShotResult; tick: number; firedColor: BubbleSlot; }

export function Board() {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const wrapRef = useRef<HTMLDivElement | null>(null);
  const cannonRef = useRef<HTMLDivElement | null>(null);
  const angleRef = useRef<number>(90);         // straight up
  const animRef = useRef<AnimState | null>(null);
  const colorsRef = useRef<BubbleColors | null>(null);
  const boardScaleRef = useRef<number>(1);      // board-logical → CSS-pixel scale
  const [size, setSize] = useState<{ w: number; h: number }>({ w: 360, h: 630 });
  const [showHints, setShowHints] = useState(false);
  const state = useRunState();
  const actions = useRunActions();

  // Resize observer — update canvas size when container resizes
  useLayoutEffect(() => {
    const wrap = wrapRef.current;
    if (!wrap) return;
    const ro = new ResizeObserver(([entry]) => {
      if (!entry) return;
      const { width, height } = entry.contentRect;
      setSize({ w: Math.floor(width), h: Math.floor(height) });
    });
    ro.observe(wrap);
    return () => ro.disconnect();
  }, []);

  // Canvas backing-store setup — sized for DPR; transform set per-frame in render loop
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    canvas.width = size.w * dpr;
    canvas.height = size.h * dpr;
    canvas.style.width = `${size.w}px`;
    canvas.style.height = `${size.h}px`;
    colorsRef.current = readBubbleColors(canvas);
  }, [size]);

  // rAF render loop — reads from React state + mutable refs
  useEffect(() => {
    let raf = 0;
    const draw = () => {
      const canvas = canvasRef.current;
      if (canvas && colorsRef.current) {
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const dpr = window.devicePixelRatio || 1;
          // Scale board logical coords (board.cols * tileDiameter wide) to canvas CSS pixels
          const boardLogicalW = state.board.cols * state.board.tileDiameter;
          const boardLogicalH = state.board.rows * state.board.tileDiameter * SQRT3_2 + state.board.tileDiameter;
          const boardScale = size.w / boardLogicalW;
          boardScaleRef.current = boardScale;
          ctx.setTransform(dpr * boardScale, 0, 0, dpr * boardScale, 0, 0);

          const anim = animRef.current;
          const inFlightPos = anim
            ? anim.shot.path[Math.min(anim.tick, anim.shot.path.length - 1)]
            : null;
          const rs: RenderState = {
            board: state.board,
            tileDiameter: state.board.tileDiameter,
            angleDeg: angleRef.current,
            nextBubble: state.nextBubble,
            // Use firedColor captured at fire time — state.nextBubble has already advanced
            inFlight: (anim && inFlightPos)
              ? { pos: inFlightPos, color: anim.firedColor }
              : null,
            colors: colorsRef.current,
            width: boardLogicalW,
            height: boardLogicalH,
          };
          renderFrame(ctx, rs);

          if (anim) {
            anim.tick += 1;
            if (anim.tick >= anim.shot.path.length) {
              animRef.current = null;
            }
          }
        }
      }

      // Sync cannon DOM rotation — done here so it matches the render loop cadence
      if (cannonRef.current) {
        cannonRef.current.style.setProperty('--angle', `${angleRef.current}deg`);
      }

      raf = requestAnimationFrame(draw);
    };
    raf = requestAnimationFrame(draw);
    return () => cancelAnimationFrame(raf);
  }, [state, size]);

  // Pointer input — drag-to-aim, release-to-fire (move events throttled to rAF)
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    let pendingMove: { x: number; y: number } | null = null;
    let moveRaf = 0;

    function toBoard(cssX: number, cssY: number) {
      const rect = canvas!.getBoundingClientRect();
      const s = boardScaleRef.current;
      return { x: (cssX - rect.left) / s, y: (cssY - rect.top) / s };
    }

    function flush() {
      moveRaf = 0;
      if (!pendingMove) return;
      const bp = toBoard(pendingMove.x, pendingMove.y);
      angleRef.current = aim(angleFromPointer(bp, state.board));
      bus.emit('aimUpdated', { angleDeg: angleRef.current });
      pendingMove = null;
    }

    function onDown(e: PointerEvent) {
      pendingMove = { x: e.clientX, y: e.clientY };
      if (!moveRaf) moveRaf = requestAnimationFrame(flush);
      canvas!.setPointerCapture(e.pointerId);
    }

    function onMove(e: PointerEvent) {
      pendingMove = { x: e.clientX, y: e.clientY };
      if (!moveRaf) moveRaf = requestAnimationFrame(flush);
    }

    function onUp(e: PointerEvent) {
      if (moveRaf) { cancelAnimationFrame(moveRaf); moveRaf = 0; }
      if (!animRef.current && state.nextBubble !== null) {
        // Final angle update from release position
        const bp = toBoard(e.clientX, e.clientY);
        angleRef.current = aim(angleFromPointer(bp, state.board));
        const firedColor = state.nextBubble;
        const result = simulateShot(state.board, angleRef.current, firedColor);
        animRef.current = { shot: result, tick: 0, firedColor };
        actions.recordShot(angleRef.current);
      }
      canvas!.releasePointerCapture(e.pointerId);
    }

    function onContext(e: MouseEvent) {
      e.preventDefault();
      bus.emit('swapRequested', {});
    }

    canvas.addEventListener('pointerdown', onDown);
    canvas.addEventListener('pointermove', onMove);
    canvas.addEventListener('pointerup', onUp);
    canvas.addEventListener('contextmenu', onContext);
    return () => {
      canvas.removeEventListener('pointerdown', onDown);
      canvas.removeEventListener('pointermove', onMove);
      canvas.removeEventListener('pointerup', onUp);
      canvas.removeEventListener('contextmenu', onContext);
      if (moveRaf) cancelAnimationFrame(moveRaf);
    };
  }, [state.board, state.nextBubble, actions]);

  // Keyboard input
  useEffect(() => attachKeyboard({
    getAngle: () => angleRef.current,
    setAngle: (a) => {
      angleRef.current = aim(a);
      bus.emit('aimUpdated', { angleDeg: angleRef.current });
    },
    fire: () => {
      if (animRef.current || state.nextBubble === null) return;
      const firedColor = state.nextBubble;
      const result = simulateShot(state.board, angleRef.current, firedColor);
      animRef.current = { shot: result, tick: 0, firedColor };
      actions.recordShot(angleRef.current);
    },
    swap: () => bus.emit('swapRequested', {}),
    restart: () => bus.emit('restartRequested', {}),
    toggleHints: () => setShowHints(h => !h),
  }), [state.board, state.nextBubble, actions]);

  return (
    <div ref={wrapRef} className="fp-board-wrap" role="application" aria-label="FizzPop playfield">
      <canvas
        ref={canvasRef}
        className="fp-canvas"
        tabIndex={0}
        aria-label="Bubble playfield. Use arrow keys to aim, Space to fire."
      />
      <AnimLayer />
      <div ref={cannonRef} className="fp-cannon" aria-hidden="true" />
      <button
        className="fp-queue-pill"
        aria-label={`Swap with queued bubble (${describeBubble(state.queuedBubble)})`}
        onClick={() => bus.emit('swapRequested', {})}
      >
        {glyphFor(state.queuedBubble)}
      </button>
      {showHints && (
        <div className="fp-hints-overlay" role="dialog" aria-modal="true" aria-label="Keyboard shortcuts">
          <button className="fp-hints-close" onClick={() => setShowHints(false)} aria-label="Close">×</button>
          <table className="fp-hints-table">
            <tbody>
              <tr><td>← / →</td><td>Rotate aim (tap 4°, hold 0.8°/frame)</td></tr>
              <tr><td>Space</td><td>Fire</td></tr>
              <tr><td>S</td><td>Swap queue</td></tr>
              <tr><td>R</td><td>Restart</td></tr>
              <tr><td>?</td><td>This help</td></tr>
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
