import { useEffect, useRef, useState } from 'react';
import { bus } from '../../lib/bus.js';
import { Confetti } from './Confetti.js';
import { GameOverOverlay } from './GameOverOverlay.js';
import { startAnimLoop } from './anim-loop.js';
import './anim.css';

export function AnimLayer() {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const [winning, setWinning] = useState(false);
  const [losing, setLosing] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const stop = startAnimLoop(canvas);
    return stop;
  }, []);

  useEffect(() => {
    const offs = [
      bus.on('gameWon', () => { setWinning(true); }),
      bus.on('gameLost', () => { setLosing(true); }),
      bus.on('gameStarted', () => { setWinning(false); setLosing(false); }),
    ];
    return () => offs.forEach((off) => off());
  }, []);

  return (
    <div className="fp-anim-layer">
      <canvas ref={canvasRef} className="fp-anim-canvas" aria-hidden="true" />
      {winning && <Confetti onDone={() => setWinning(false)} />}
      {losing && <GameOverOverlay onDone={() => setLosing(false)} />}
    </div>
  );
}
