import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus.js';

export function LiveRegion() {
  const [msg, setMsg] = useState('');

  useEffect(() => {
    const offs = [
      bus.on('bubbleFired', () => setMsg('Shot fired.')),
      bus.on('clusterPopped', ({ size }) => setMsg(`${size} bubbles popped.`)),
      bus.on('floatersDropped', ({ count }) => setMsg(`${count} bubbles dropped.`)),
      bus.on('pityChanged', ({ remaining }) => {
        if (remaining === 1) setMsg('Pity timer at 1. Next miss drops a row.');
      }),
      bus.on('gameWon', ({ shotsUsed }) => setMsg(`Puzzle cleared in ${shotsUsed} shots.`)),
      bus.on('gameLost', () => setMsg('Game over.')),
    ];
    return () => offs.forEach((off) => off());
  }, []);

  return (
    <div
      className="fp-sr-only"
      role="status"
      aria-live="polite"
      aria-atomic="true"
    >
      {msg}
    </div>
  );
}
