import type { BubbleColors } from './render.js';

export type { BubbleColors };

export function readBubbleColors(el: HTMLElement): BubbleColors {
  const cs = getComputedStyle(el);
  return {
    bubbles: [1, 2, 3, 4, 5, 6].map(i =>
      cs.getPropertyValue(`--bubble-${i}`).trim() || '#888888'
    ).concat([cs.getPropertyValue('--num-7').trim() || '#1c1c1e']),
    ink: cs.getPropertyValue('--ink').trim() || '#1c1c1e',
    paper: cs.getPropertyValue('--paper').trim() || '#ffffff',
    conflict: cs.getPropertyValue('--conflict').trim() || '#ff3b30',
  };
}
