import { useEffect, useState } from 'react';
import { useStreakState } from '../../state/streak-store.js';
import { useRunState, useRunActions } from '../../state/store.js';
import { dailyDifficulty } from '../../engine/index.js';
import { isoDate, parseDateParam, dailyPlayfieldFor } from './daily-loader.js';
import { CalendarSheet } from './CalendarSheet.js';
import { ShareTile } from './ShareTile.js';

function capitalize(s: string): string {
  return s ? (s[0]?.toUpperCase() ?? '') + s.slice(1) : s;
}

export function DailyCard() {
  const streak = useStreakState();
  const run = useRunState();
  const actions = useRunActions();
  const [showCal, setShowCal] = useState(false);
  const [showShare, setShowShare] = useState(false);

  const today = new Date();
  const todayIso = isoDate(today);
  const cfg = dailyDifficulty(today);
  const completed = streak.completed.includes(todayIso);
  const bestShots = streak.bestByMode.daily?.[todayIso];

  const dayName = today.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });

  // URL param `?d=YYYY-MM-DD` → start that day's puzzle on first mount.
  useEffect(() => {
    const d = parseDateParam();
    if (d) actions.startRun({ mode: 'daily', date: d });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Show share when daily just-completed.
  useEffect(() => {
    if (run.mode === 'daily' && run.solved) setShowShare(true);
  }, [run.solved, run.mode]);

  function playToday() {
    history.pushState(null, '', `?d=${todayIso}`);
    actions.startRun({ mode: 'daily', date: today });
  }

  const isActiveDaily = run.mode === 'daily' && !run.solved && !run.lost;

  return (
    <div className="fp-daily-card">
      <div className="fp-daily-info">
        <p className="fp-daily-eyebrow">Today&apos;s puzzle · {dayName}</p>
        <h2 className="fp-daily-title">{capitalize(cfg.mode)} · ≤{cfg.par} shots</h2>
        <p className="fp-daily-pledge">✓ Daily Solvable</p>
        {streak.current > 0 && <p className="fp-daily-streak">🔥 streak {streak.current}</p>}
      </div>
      <div className="fp-daily-actions">
        {completed && bestShots != null ? (
          <p className="fp-daily-done">Solved in {bestShots} shots ✓</p>
        ) : isActiveDaily ? (
          <button className="fp-daily-btn primary" onClick={playToday}>Resume</button>
        ) : (
          <button className="fp-daily-btn primary" onClick={playToday}>Play today</button>
        )}
        <button
          className="fp-daily-btn ghost"
          aria-label="Calendar archive"
          onClick={() => setShowCal(true)}
        >📅</button>
        {showShare && <ShareTile onDismiss={() => setShowShare(false)} />}
      </div>
      {showCal && <CalendarSheet onClose={() => setShowCal(false)} />}
    </div>
  );
}
